import { useState, useEffect } from "react";
import axios from "axios";
import Sidebar from "./Sidebar";
import Topbar from "./Topbar";

export default function Projectdetails() {

  const [showForm, setShowForm] = useState(false);
  const [projects, setProjects] = useState([]);

  const [formData, setFormData] = useState({
    name: "",
    location: "",
    budget: "",
    floors: "",
    start_date: "",
    end_date: "",
    description: "",
    status: "Active"
  });

  const today = new Date().toISOString().split("T")[0];

  // LOAD PROJECTS
  useEffect(() => {
    fetchProjects();
  }, []);

  const fetchProjects = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/projects");
      setProjects(res.data);
    } catch (err) {
      console.error(err);
    }
  };

  // HANDLE INPUT
  const handleChange = (e) => {

    const { name, value } = e.target;

    if (name === "budget" && value > 100000000) return; // 10 Cr
    if (name === "floors" && value > 30) return;

    setFormData({
      ...formData,
      [name]: value
    });
  };

  // ADD PROJECT
  const handleSubmit = async () => {

    if (!formData.projectName) {
      alert("Project name required");
      return;
    }

    try {

      axios.post("http://localhost:5000/api/projects/add", formData)
      ;

      fetchProjects();

      setFormData({
        nameame: "",
        location: "",
        budget: "",
        floors: "",
        start_date: "",
        end_dfinate: "",
        description: "",
        status: "Active"
      });

      setShowForm(false);

    } catch (err) {

      console.error(err);
      alert("Error adding project");

    }

  };

  return (

    <div className="flex bg-gray-100 min-h-screen">

      <Sidebar />

      <div className="flex-1 flex flex-col">

        <Topbar />

        <div className="p-8">

          {/* PROJECT LIST */}

          {!showForm && (
            <>

              <div className="flex justify-between items-center mb-6">

                <div>
                  <h1 className="text-3xl font-bold">
                    Project Details
                  </h1>

                  <p className="text-gray-500">
                    Manage all construction projects
                  </p>
                </div>

                <button
                  onClick={() => setShowForm(true)}
                  className="bg-orange-500 text-white px-6 py-3 rounded-xl"
                >
                  + Add New Project
                </button>

              </div>

              {projects.length === 0 && (

                <div className="bg-white rounded-2xl shadow flex flex-col items-center justify-center py-24 text-gray-500">

                  <div className="text-6xl mb-4">
                    📂
                  </div>

                  <p>
                    No projects found. Add your first project.
                  </p>

                </div>

              )}

              {projects.length > 0 && (

                <div className="grid grid-cols-3 gap-6">

                  {projects.map((project) => (

                    <div
                      key={project.id}
                      className="bg-white p-6 rounded-2xl shadow"
                    >

                      <h3 className="text-xl font-bold mb-2">
                        {project.projectName}
                      </h3>

                      <p className="text-gray-500">
                        📍 {project.location}
                      </p>

                      <p>
                        💰 ₹{Number(project.budget).toLocaleString()}
                      </p>

                      <p>
                        🏢 Floors: {project.floors}
                      </p>

                      <p className="text-sm">
                        📅 {project.startDate} → {project.endDate}
                      </p>

                      <span className="inline-block mt-2 px-3 py-1 bg-green-100 text-green-700 text-sm rounded-full">

                        {project.status}

                      </span>

                    </div>

                  ))}

                </div>

              )}

            </>
          )}

          {/* ADD PROJECT FORM */}

          {showForm && (

            <div className="bg-white p-8 rounded-2xl shadow">

              <h2 className="text-2xl font-semibold mb-6">
                Add New Project
              </h2>

              <div className="grid grid-cols-2 gap-6">

                <input
                  type="text"
                  name="projectName"
                  value={formData.projectName}
                  onChange={handleChange}
                  placeholder="Project Name"
                  className="border p-3 rounded-xl"
                />

                <input
                  type="text"
                  name="location"
                  value={formData.location}
                  onChange={handleChange}
                  placeholder="Location"
                  className="border p-3 rounded-xl"
                />

                <input
                  type="number"
                  name="budget"
                  value={formData.budget}
                  onChange={handleChange}
                  max="100000000"
                  placeholder="Budget (Max 10Cr)"
                  className="border p-3 rounded-xl"
                />

                <input
                  type="number"
                  name="floors"
                  value={formData.floors}
                  onChange={handleChange}
                  max="30"
                  placeholder="Floors"
                  className="border p-3 rounded-xl"
                />

                <input
                  type="date"
                  name="startDate"
                  value={formData.startDate}
                  onChange={handleChange}
                  max={today}
                  className="border p-3 rounded-xl"
                />

                <input
                  type="date"
                  name="endDate"
                  value={formData.endDate}
                  onChange={handleChange}
                  min={formData.startDate}
                  className="border p-3 rounded-xl"
                />

              </div>

              <textarea
                name="description"
                value={formData.description}
                onChange={handleChange}
                placeholder="Project Description"
                className="border p-3 rounded-xl w-full mt-6"
              />

              <select
                name="status"
                value={formData.status}
                onChange={handleChange}
                className="border p-3 rounded-xl w-full mt-6"
              >
                <option value="Active">Active</option>
                <option value="Completed">Completed</option>
                <option value="On Hold">On Hold</option>
              </select>

              <div className="flex gap-4 mt-6">

                <button
                  onClick={handleSubmit}
                  className="bg-orange-500 text-white px-6 py-3 rounded-xl"
                >
                  Add Project
                </button>

                <button
                  onClick={() => setShowForm(false)}
                  className="bg-gray-300 px-6 py-3 rounded-xl"
                >
                  Cancel
                </button>

              </div>

            </div>

          )}

        </div>

      </div>

    </div>

  );

}
